var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"부상당한 아샤를 노리고 있어.\xA0","JPN":"怪我をしたアーシャを狙っている。\xA0","ENG":"It's after Asha.\xA0","TWN":"它是衝著受傷的阿莎來的。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만…… 다시 힘을 쓰게 된다면 아샤는 물론 나까지 휘말릴지도 모른다.","JPN":"でも……もう一度力を使ったら、アーシャとともに自分まで巻き添えをくらうかもしれない。","ENG":"But... if I use my powers again, Asha will also get caught in it as well as me.","TWN":"但是……如果再使用能力，不僅是阿莎，連我也很可能會受傷。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"생각해야 한다. 아디트야!","JPN":"考えろ、アーディティヤ！","ENG":"Think, Aditya!","TWN":"阿迪亞，冷靜想想！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"무기를 시동하고, 힘을 제어할 방법을 생각해 내야 해!","JPN":"武器を始動し、力をコントロールする方法を考えるんだ！","ENG":"Think of a way to activate the weapon and control it!","TWN":"想想該怎麼控制力量！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>만트라 코드</color>를 요구합니다.","JPN":"<color=#ffd34c>マントラコード</color>を要求します。","ENG":"Requesting <color=#ffd34c>mantra code</color>.","TWN":"需要<color=#ffd34c>曼陀羅代碼</color>。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L16_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"만트라…… 코드……?","JPN":"マントラ……コード……？","ENG":"Mantra... code...?","TWN":"曼陀羅……代碼……?"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"병기개발국에서 특수 제작한 무장입니다.","JPN":"兵器開発局が製作した特殊装備です。","ENG":"It is a custom armament made by the Weapon Development Bureau.","TWN":"這是兵器開發局特製的武裝。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"당신의 힘을 제어할 수 있도록 CRF 제어 계산, 좌표 계산 등 각종 연산 기능을 넣은 시동 무기예요.","JPN":"あなたの力を制御するために、CRF制御の演算、座標計算など、あらゆる演算機能を搭載した始動武器です。","ENG":"It has various computational functions such as CRF control calculation, coordinates calculation, and more so that you will be able to control your powers.","TWN":"這個武裝內建CRF控制計算、座標計算等各種運算功能，方便你你能夠控制自己的力量。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"하지만, 각종 연산 기능은 무기가 시동 되었을 때만 작동합니다.","JPN":"しかし、これらの演算機能は、武器を始動した時のみ使用できます。","ENG":"However, the computational functions will only work when the weapon is activated.","TWN":"不過這些運算功能只有在武器啟動時才會運作。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"일종의 활성화 코드가 필요한 셈인데요.","JPN":"つまり活性化コードが必要になるということです。","ENG":"For that, you will need an activation code.","TWN":"因此需要輸入代碼。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"병기개발국은 이를 <color=#ffd34c>만트라 코드</color>라고 정의했습니다.","JPN":"兵器開発局は、これを<color=#ffd34c>マントラコード</color>と名づけました。","ENG":"The Weapon Development Bureau has defined this as the <color=#ffd34c>mantra code</color>.","TWN":"兵器開發局將代碼命名為<color=#ffd34c>曼陀羅代碼</color>。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이 무장의 활성화 코드는…….","JPN":"この武装を活性化するためのコードは……","ENG":"The code to activate this armament is...","TWN":"這個武裝的啟動代碼是……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"크헉!","JPN":"がはっ！","ENG":"Kuh!","TWN":"嚇呃！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤! 위험해!","JPN":"アーシャ、危ない！","ENG":"Asha! Watch out!","TWN":"阿莎！危險！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"모래 폭풍이……!","JPN":"砂嵐が……！","ENG":"The sandstorm...!","TWN":"沙塵暴……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤! 아샤! 대답해!!","JPN":"アーシャ！　アーシャ！　返事しろ！！","ENG":"Asha! Asha! Answer me!","TWN":"阿莎！阿莎！回答我！！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시…… 제 욕심이었던 걸까요?","JPN":"やっぱり……行き過ぎた欲望だったんでしょうか？","ENG":"Was I... being too greedy?","TWN":"果然……是我的私慾害的嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"욕심이 아니다! 정신만 차리면 같이 살아갈 수 있어!","JPN":"そんなことはない！　気をたしかに持てば一緒に生きて帰れる！","ENG":"You weren't! If you stay with me, we both can make it out of here!","TWN":"不是！你振作一點，我們可以一起活下去的！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이 침식체. 절 똑바로 바라보고 있어요.","JPN":"この侵食体。私だけをまっすぐ見ています。","ENG":"This C.O., it's looking right at me.","TWN":"這個侵蝕體，它在盯著我。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"목소리가 들려요. 다들 태양을 가까이한 대가를 받은 거래요.","JPN":"声が聞こえます。みんな太陽に近づいた代償を払うと。","ENG":"I can hear voices. They're saying that this is the price for getting too close to the sun.","TWN":"我有聽到聲音，他們說這是靠近太陽的代價。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아니야! 모든 건 내 탓이다!","JPN":"違う！　すべて私のせいだ！","ENG":"NO! It's all my fault!","TWN":"不是的！這全都是我的錯！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 잘못이야…… 내가 멍청하게 힘을 개방하지만 않았어도……!","JPN":"私の失態だ……むやみに力を解放さえしなければ……！","ENG":"It's my fault... If I hadn't foolishly unleashed my powers...!","TWN":"都是我的錯……要不是我愚蠢地釋放力量……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……아디트야 님 잘못이 아니에요.","JPN":"……アーディティヤ様にはなんの非もありません。","ENG":"...It's not your fault, Miss Aditya.","TWN":"……這不是阿迪亞的錯。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"말도 안 되는 억지를 부려서…… 제가 그 죗값을 받는 거라고 생각해요…….","JPN":"私がわがままを言い過ぎたから……そのつけが回ってきたんです……","ENG":"I'm getting punished for... asking for those ridiculous requests...","TWN":"都怪我太強求……是我活該……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"꼭 기억을 되찾으셨으면 좋겠어요.","JPN":"必ず記憶を取り戻してくださいね。","ENG":"I hope you find your memories.","TWN":"希望你能找回記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"짧은 시간이었지만, 전…….","JPN":"短い間でしたけど、私……","ENG":"We didn't know each other for that long, but...","TWN":"雖然我們認識的時間很短，但我……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"안돼…… 아샤. 안돼!!","JPN":"そんな……アーシャ、ダメだ！！","ENG":"No... Asha. NO!!","TWN":"不可以……阿莎。不要！！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};